# -*- coding: utf-8 -*-
"""Plantillas Jinja2 incrustadas (no requiere carpeta templates/).
El escape automatico de HTML sigue activo porque los nombres terminan en .html."""

TEMPLATES = {
    'base.html': '<!doctype html><html lang="es"><head>\n<meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">\n<title>{% block title %}Validación{% endblock %} - Validación de Enlaces</title>\n<style>\n body{margin:0;font-family:\'Segoe UI\',system-ui,sans-serif;background:#fff;color:#1f2937}\n header{display:flex;align-items:center;justify-content:space-between;\n        padding:12px 24px;border-bottom:1px solid #e5e7eb;flex-wrap:wrap;gap:8px}\n header h1{font-size:1.1rem;margin:0}\n header h1 a{color:inherit;text-decoration:none}\n .btn{display:inline-block;padding:6px 12px;border-radius:6px;border:1px solid #d1d5db;\n      background:#fff;color:#374151;text-decoration:none;font-size:.78rem;cursor:pointer}\n .btn-azul{background:#2563eb;border-color:#2563eb;color:#fff}\n .btn-verde{border-color:#059669;color:#059669}\n .btn-naranja{border-color:#d97706;color:#d97706}\n .btn-rojo{border-color:#dc2626;color:#dc2626}\n .btn-gris{background:#6b7280;border-color:#6b7280;color:#fff}\n .flash{max-width:1500px;margin:10px auto 0;padding:8px 14px;border-radius:8px;font-size:.85rem}\n .flash.ok{background:#d1fae5;color:#065f46}\n .flash.error{background:#fee2e2;color:#991b1b}\n .contenido{max-width:1500px;margin:0 auto;padding:20px 24px}\n table{width:100%;border-collapse:collapse;font-size:.8rem}\n th{text-align:left;padding:6px 4px;border-bottom:2px solid #e5e7eb}\n td{padding:8px 4px;border-bottom:1px solid #f3f4f6;vertical-align:middle}\n label{display:block;font-size:.8rem;color:#6b7280;margin-top:10px}\n input,select,textarea{width:100%;padding:6px;border:1px solid #d1d5db;\n   border-radius:6px;box-sizing:border-box;font-family:inherit}\n .chip{display:inline-block;padding:1px 8px;border-radius:10px;font-size:.68rem;font-weight:700}\n .chip.verde{background:#d1fae5;color:#065f46}\n .chip.ambar{background:#fef3c7;color:#92400e}\n .chip.rojo{background:#fee2e2;color:#991b1b}\n .usuario{font-size:.78rem;color:#6b7280}\n</style></head><body>\n<header>\n  <h1><a href="{{ url_for(\'main.dashboard\') }}">🧵 Validación de Enlaces</a></h1>\n  <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap">\n    {% if current_user.is_authenticated %}\n      <a class="btn btn-verde" href="{{ url_for(\'main.reporte_avance\') }}">📊 Reporte de Avance</a>\n      {% if current_user.es_editor %}\n        <a class="btn btn-azul" href="{{ url_for(\'main.nuevo\') }}">+ Nuevo Enlace</a>\n      {% endif %}\n      <a class="btn" href="{{ url_for(\'main.papelera\') }}">🗑 Papelera</a>\n      <span class="usuario">{{ current_user.username }} ({{ current_user.rol }})</span>\n      <a class="btn" href="{{ url_for(\'auth.logout\') }}">Salir</a>\n    {% endif %}\n  </div>\n</header>\n{% with msgs = get_flashed_messages(with_categories=true) %}\n  {% for cat, m in msgs %}<div class="flash {{ cat }}">{{ m }}</div>{% endfor %}\n{% endwith %}\n<div class="contenido">{% block content %}{% endblock %}</div>\n</body></html>\n',

    'completar.html': '{% extends "base.html" %}{% block title %}Completar {{ letra }}{% endblock %}\n{% block content %}\n<h2>Completar Extremo {{ letra }}</h2>\n<p><b>{{ e.anillo }} | {{ e.nombre }}</b> · {{ e.capacidad }} hilos ·\n   Estado: {{ e.estado }} ({{ e.pendiente_texto or \'completo\' }})</p>\n<form method="post">\n  <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">\n  <label>Origen (Sitio {{ letra }})</label>\n  <input name="origen" required\n         value="{{ e.origen_a if es_a else e.origen_b }}">\n  <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;max-width:640px">\n    <div><label>Sala {{ letra }}</label>\n      <input name="sala" value="{{ (e.sala_a if es_a else e.sala_b) or \'\' }}"></div>\n    <div><label>Rack {{ letra }}</label>\n      <input name="rack" value="{{ (e.rack_a if es_a else e.rack_b) or \'\' }}"></div>\n    <div><label>Posición {{ letra }}</label>\n      <input name="posicion" value="{{ (e.posicion_a if es_a else e.posicion_b) or \'\' }}"></div>\n  </div>\n  {% set otro_ok = e.b_completo if es_a else e.a_completo %}\n  <table style="margin-top:16px">\n    <tr><th style="width:60px">Fibra</th>\n        {% if otro_ok %}<th>Extremo {{ \'B\' if es_a else \'A\' }} (referencia)</th>{% endif %}\n        <th>Descripción Extremo {{ letra }}</th></tr>\n    {% for h in e.hilos %}\n    <tr><td>{{ h.numero }}</td>\n        {% if otro_ok %}\n          <td style="color:#6b7280">{{ h.descripcion_b if es_a else h.descripcion_a }}</td>\n        {% endif %}\n        <td><input name="h{{ h.numero }}"\n             value="{{ h.descripcion_a if es_a else h.descripcion_b }}"\n             placeholder="LIBRE / ODF / SIN PIGTAIL..."></td></tr>\n    {% endfor %}\n  </table>\n  <div style="margin-top:16px">\n    <button class="btn {{ \'btn-naranja\' if es_a else \'btn-azul\' }}"\n      style="{{ \'background:#d97706;color:#fff\' if es_a else \'background:#2563eb;color:#fff\' }}">\n      Guardar Extremo {{ letra }}</button>\n    <a class="btn btn-gris" href="{{ url_for(\'main.dashboard\') }}">Cancelar</a>\n  </div>\n</form>\n{% endblock %}\n',

    'dashboard.html': '{% extends "base.html" %}{% block title %}Dashboard{% endblock %}\n{% block content %}\n<form method="get" style="display:flex;gap:8px;margin-bottom:16px;flex-wrap:wrap">\n  <input name="q" value="{{ q }}" placeholder="Buscar por nombre o sitio..."\n         style="max-width:280px">\n  <select name="anillo" style="max-width:190px">\n    <option value="">Todos los anillos</option>\n    {% for a in anillos %}\n      <option {% if a==anillo %}selected{% endif %}>{{ a }}</option>\n    {% endfor %}\n  </select>\n  <button class="btn btn-azul">Buscar</button>\n  {% if q or anillo %}<a class="btn" href="{{ url_for(\'main.dashboard\') }}">Limpiar</a>{% endif %}\n</form>\n\n<div style="display:grid;grid-template-columns:1fr 1fr;gap:24px;align-items:start">\n  <div style="border:1px solid #e5e7eb;border-radius:12px;padding:16px;box-shadow:0 1px 4px rgba(0,0,0,.06)">\n    <h2 style="font-size:1rem;margin:0 0 2px">Pendientes (Incompletos)\n      <span class="chip" style="background:#dbeafe;color:#1d4ed8">{{ total_pend }}</span></h2>\n    <p style="color:#6b7280;font-size:.75rem;margin:0 0 12px">\n      Semáforo de antigüedad: <span class="chip verde">&lt;30d</span>\n      <span class="chip ambar">30–89d</span> <span class="chip rojo">≥90d</span></p>\n    <table>\n      <tr><th>Enlace</th><th>Cap.</th><th>Antigüedad</th><th>Acciones</th></tr>\n      {% for e in pend %}\n      <tr>\n        <td><strong>{{ e.anillo }} | {{ e.nombre }}</strong><br>\n          <span style="color:#9ca3af;font-size:.72rem">{{ e.origen_a or \'?\' }} → {{ e.origen_b or \'?\' }}</span><br>\n          <span style="color:#d97706;font-size:.7rem;font-weight:600">{{ e.pendiente_texto }}</span></td>\n        <td>{{ e.capacidad }}</td>\n        <td><span class="chip {{ e.semaforo }}">{{ e.dias }} días</span><br>\n          <span style="font-size:.68rem;color:#9ca3af">{{ e.creado.strftime(\'%d/%m/%Y\') }}</span></td>\n        <td>\n          <div style="display:flex;gap:4px;flex-wrap:wrap">\n          {% if current_user.es_editor %}\n            {% if not e.a_completo %}\n              <a class="btn btn-naranja" href="{{ url_for(\'main.completar\', id=e.id, lado=\'a\') }}">Completar A</a>\n            {% endif %}\n            {% if not e.b_completo %}\n              <a class="btn" style="border-color:#2563eb;color:#2563eb"\n                 href="{{ url_for(\'main.completar\', id=e.id, lado=\'b\') }}">Completar B</a>\n            {% endif %}\n            <a class="btn" href="{{ url_for(\'main.editar\', id=e.id) }}">Editar</a>\n          {% endif %}\n          <a class="btn btn-verde" href="{{ url_for(\'main.exportar\', id=e.id) }}">Exportar</a>\n          {% if current_user.es_editor %}\n            <form method="post" action="{{ url_for(\'main.eliminar\', id=e.id) }}"\n                  onsubmit="return confirm(\'¿Enviar a la papelera?\')" style="display:inline">\n              <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">\n              <button class="btn btn-rojo">Eliminar</button>\n            </form>\n          {% endif %}\n          </div>\n        </td>\n      </tr>\n      {% else %}\n      <tr><td colspan="4" style="color:#9ca3af">Sin resultados.</td></tr>\n      {% endfor %}\n    </table>\n    {% if paginas > 1 %}\n    <div style="margin-top:12px;display:flex;gap:6px;align-items:center">\n      {% for p in range(1, paginas+1) %}\n        {% if p == page %}<span class="btn btn-azul">{{ p }}</span>\n        {% else %}<a class="btn" href="{{ url_for(\'main.dashboard\', page=p, q=q, anillo=anillo) }}">{{ p }}</a>{% endif %}\n      {% endfor %}\n      <span style="font-size:.72rem;color:#9ca3af">Página {{ page }} de {{ paginas }}</span>\n    </div>\n    {% endif %}\n  </div>\n\n  <div style="border:1px solid #e5e7eb;border-radius:12px;padding:16px;box-shadow:0 1px 4px rgba(0,0,0,.06)">\n    <h2 style="font-size:1rem;margin:0 0 12px">Validados\n      <span class="chip" style="background:#d1fae5;color:#065f46">{{ valid|length }}</span></h2>\n    <table>\n      <tr><th>Enlace</th><th>Cap.</th><th>Creado</th><th>Acciones</th></tr>\n      {% for e in valid %}\n      <tr>\n        <td><strong>{{ e.anillo }} | {{ e.nombre }}</strong><br>\n          <span style="color:#9ca3af;font-size:.72rem">{{ e.origen_a }} ⇄ {{ e.origen_b }}</span></td>\n        <td>{{ e.capacidad }}</td>\n        <td style="font-size:.72rem">{{ e.creado.strftime(\'%d/%m/%Y\') }}</td>\n        <td><div style="display:flex;gap:4px;flex-wrap:wrap">\n          <a class="btn" href="{{ url_for(\'main.ver\', id=e.id) }}">Ver</a>\n          {% if current_user.es_editor %}\n            <a class="btn" href="{{ url_for(\'main.editar\', id=e.id) }}">Editar</a>\n          {% endif %}\n          <a class="btn btn-verde" href="{{ url_for(\'main.exportar\', id=e.id) }}">Exportar</a>\n        </div></td>\n      </tr>\n      {% else %}\n      <tr><td colspan="4" style="color:#9ca3af">Sin resultados.</td></tr>\n      {% endfor %}\n    </table>\n  </div>\n</div>\n{% endblock %}\n',

    'editar.html': '{% extends "base.html" %}{% block title %}Editar{% endblock %}\n{% block content %}\n<div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:8px">\n  <div><h2 style="margin:0">Editar Enlace</h2>\n    <p style="color:#6b7280;font-size:.78rem;margin:4px 0 0">\n      Puedes corregir cabecera, Extremos A/B y descripciones.</p></div>\n  <div style="display:flex;gap:6px">\n    <a class="btn" href="{{ url_for(\'main.dashboard\') }}">&larr; Volver</a>\n    <a class="btn" href="{{ url_for(\'main.ver\', id=e.id) }}">Ver reporte</a>\n    <a class="btn btn-verde" href="{{ url_for(\'main.exportar\', id=e.id) }}">Exportar</a>\n  </div>\n</div>\n\n<form method="post" style="margin-top:16px">\n  <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">\n  <div style="display:grid;grid-template-columns:2fr 1.2fr 1fr;gap:18px">\n    <div>\n      <label>Nombre del Enlace</label>\n      <select name="nombre_sel">\n        <option value="__actual__" selected>(Mantener actual)</option>\n      </select>\n      <input name="nombre_manual" placeholder="(Opcional) Nombre manual del enlace"\n             style="margin-top:6px" maxlength="120">\n      <div style="color:#6b7280;font-size:.72rem;margin-top:6px">\n        Actual: <b>{{ e.anillo }} | {{ e.nombre }}</b></div>\n      <label>Anillo</label>\n      <select name="anillo">{% for a in anillos %}\n        <option {% if a==e.anillo %}selected{% endif %}>{{ a }}</option>{% endfor %}</select>\n    </div>\n    <div>\n      <label>Tipo de Cable</label>\n      <select name="tipo_cable">{% for t in tipos %}\n        <option {% if t==e.tipo_cable %}selected{% endif %}>{{ t }}</option>{% endfor %}</select>\n      <label>Longitud Tramo Total</label>\n      <input name="longitud" value="{{ e.longitud or \'\' }}" maxlength="40">\n    </div>\n    <div>\n      <label>Capacidad (N hilos)</label>\n      <select name="capacidad">{% for c in capacidades %}\n        <option {% if c==e.capacidad %}selected{% endif %}>{{ c }}</option>{% endfor %}</select>\n      <div style="color:#6b7280;font-size:.7rem;margin-top:4px">\n        Si reduces capacidad, se eliminan hilos mayores a N.</div>\n    </div>\n  </div>\n\n  <div style="display:grid;grid-template-columns:1fr 1fr;gap:18px;margin-top:18px">\n    <div style="background:#f9fafb;border:1px solid #e5e7eb;border-radius:10px;padding:14px">\n      <h4 style="margin:0 0 8px;font-size:.9rem">Extremo A</h4>\n      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px">\n        <div><label>Origen A</label>\n          <input name="origen_a" list="sitios" value="{{ e.origen_a }}"></div>\n        <div><label>Sala A</label><input name="sala_a" value="{{ e.sala_a or \'\' }}"></div>\n        <div><label>Rack A</label><input name="rack_a" value="{{ e.rack_a or \'\' }}"></div>\n      </div>\n      <div style="max-width:32%"><label>Posición A</label>\n        <input name="posicion_a" value="{{ e.posicion_a or \'\' }}"></div>\n    </div>\n    <div style="background:#f9fafb;border:1px solid #e5e7eb;border-radius:10px;padding:14px">\n      <h4 style="margin:0 0 8px;font-size:.9rem">Extremo B</h4>\n      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px">\n        <div><label>Origen B</label>\n          <input name="origen_b" list="sitios" value="{{ e.origen_b }}"></div>\n        <div><label>Sala B</label><input name="sala_b" value="{{ e.sala_b or \'\' }}"></div>\n        <div><label>Rack B</label><input name="rack_b" value="{{ e.rack_b or \'\' }}"></div>\n      </div>\n      <div style="max-width:32%"><label>Posición B</label>\n        <input name="posicion_b" value="{{ e.posicion_b or \'\' }}"></div>\n      <div style="color:#6b7280;font-size:.7rem;margin-top:6px">\n        Nota: si completas B por aquí, igual puedes ir a "Completar B" si está pendiente.</div>\n    </div>\n  </div>\n  <datalist id="sitios">{% for s in sitios %}<option value="{{ s }}">{% endfor %}</datalist>\n\n  <h4 style="margin-top:20px">Descripciones de hilos</h4>\n  <table><tr><th style="width:60px">Fibra</th><th>Extremo A</th><th>Extremo B</th></tr>\n    {% for h in e.hilos %}\n    <tr><td>{{ h.numero }}</td>\n        <td><input name="a{{ h.numero }}" value="{{ h.descripcion_a }}"></td>\n        <td><input name="b{{ h.numero }}" value="{{ h.descripcion_b }}"></td></tr>\n    {% endfor %}\n  </table>\n  <div style="margin-top:16px">\n    <button class="btn btn-azul">Guardar cambios</button>\n    <a class="btn btn-gris" href="{{ url_for(\'main.dashboard\') }}">Cancelar</a>\n  </div>\n</form>\n{% endblock %}\n',

    'error.html': '{% extends "base.html" %}{% block title %}Error {{ codigo }}{% endblock %}\n{% block content %}\n<div style="text-align:center;margin-top:60px">\n  <h1 style="font-size:3rem;color:#dc2626">{{ codigo }}</h1>\n  <p>{{ mensaje }}</p>\n  <a class="btn btn-azul" href="{{ url_for(\'main.dashboard\') }}">Ir al dashboard</a>\n</div>\n{% endblock %}\n',

    'login.html': '{% extends "base.html" %}{% block title %}Acceso{% endblock %}\n{% block content %}\n<div style="max-width:360px;margin:60px auto">\n  <h2>Iniciar sesión</h2>\n  <form method="post">\n    <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">\n    <label>Usuario</label><input name="username" required autofocus>\n    <label>Contraseña</label><input name="password" type="password" required>\n    <button class="btn btn-azul" style="margin-top:14px;width:100%">Ingresar</button>\n  </form>\n  <p style="color:#9ca3af;font-size:.72rem;margin-top:14px">\n    Demo: admin/admin123 (editor) · lector/lector123 (solo lectura)</p>\n</div>\n{% endblock %}\n',

    'nuevo.html': '{% extends "base.html" %}{% block title %}Nuevo Enlace{% endblock %}\n{% block content %}\n<h2>Nuevo Enlace</h2>\n<p style="color:#6b7280;font-size:.8rem">Se crea la ficha; luego usa\n  <b>Completar A</b> y <b>Completar B</b> desde el dashboard.</p>\n<form method="post" style="max-width:640px">\n  <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">\n  <label>Anillo</label>\n  <select name="anillo">{% for a in anillos %}<option>{{ a }}</option>{% endfor %}</select>\n  <label>Nombre del enlace (SITIO A - SITIO B)</label>\n  <input name="nombre" required maxlength="120">\n  <label>Capacidad (hilos)</label>\n  <select name="capacidad">{% for c in capacidades %}\n    <option {% if c==48 %}selected{% endif %}>{{ c }}</option>{% endfor %}</select>\n  <label>Origen A (sugerido)</label>\n  <input name="origen_a" list="sitios">\n  <label>Origen B (sugerido)</label>\n  <input name="origen_b" list="sitios">\n  <datalist id="sitios">{% for s in sitios %}<option value="{{ s }}">{% endfor %}</datalist>\n  <div style="margin-top:16px">\n    <button class="btn btn-azul">Crear enlace</button>\n    <a class="btn btn-gris" href="{{ url_for(\'main.dashboard\') }}">Cancelar</a>\n  </div>\n</form>\n{% endblock %}\n',

    'papelera.html': '{% extends "base.html" %}{% block title %}Papelera{% endblock %}\n{% block content %}\n<h2>🗑 Papelera</h2>\n<p style="color:#6b7280;font-size:.8rem">Enlaces eliminados (borrado lógico).\n  Puedes restaurarlos.</p>\n<table style="max-width:900px">\n  <tr><th>Enlace</th><th>Eliminado por</th><th>Fecha</th><th></th></tr>\n  {% for e in enlaces %}\n  <tr>\n    <td><b>{{ e.anillo }} | {{ e.nombre }}</b></td>\n    <td>{{ e.modificado_por or \'-\' }}</td>\n    <td>{{ e.modificado_en.strftime(\'%d/%m/%Y %H:%M\') if e.modificado_en else \'-\' }}</td>\n    <td>{% if current_user.es_editor %}\n      <form method="post" action="{{ url_for(\'main.restaurar\', id=e.id) }}" style="display:inline">\n        <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">\n        <button class="btn btn-verde">Restaurar</button>\n      </form>{% endif %}</td>\n  </tr>\n  {% else %}\n  <tr><td colspan="4" style="color:#9ca3af">La papelera está vacía.</td></tr>\n  {% endfor %}\n</table>\n<a class="btn btn-gris" style="margin-top:14px" href="{{ url_for(\'main.dashboard\') }}">Volver</a>\n{% endblock %}\n',

    'ver.html': '{% extends "base.html" %}{% block title %}Reporte{% endblock %}\n{% block content %}\n<h2>Reporte Comparativo</h2>\n<p><b>{{ e.anillo }} | {{ e.nombre }}</b> · {{ e.capacidad }} hilos ·\n   {{ e.origen_a }} ⇄ {{ e.origen_b }} · Estado: {{ e.estado }}</p>\n{% if difs %}\n  <p style="color:#b45309">⚠ {{ difs }} hilo(s) con diferencias entre A y B.</p>\n{% else %}\n  <p style="color:#059669">✔ Todos los hilos coinciden.</p>\n{% endif %}\n<table>\n  <tr><th style="width:60px">Fibra</th><th>{{ e.origen_a or \'A\' }}</th>\n      <th>{{ e.origen_b or \'B\' }}</th><th style="width:80px">Coincide</th></tr>\n  {% for h in e.hilos %}\n  <tr style="{{ \'background:#fee2e2\' if not h.coincide else \'\' }}">\n    <td>{{ h.numero }}</td><td>{{ h.descripcion_a }}</td>\n    <td>{{ h.descripcion_b }}</td><td>{{ \'Sí\' if h.coincide else \'No\' }}</td></tr>\n  {% endfor %}\n</table>\n\n{% if historial %}\n<h4 style="margin-top:24px">Historial de cambios</h4>\n<table style="max-width:720px">\n  <tr><th>Fecha (UTC)</th><th>Usuario</th><th>Acción</th></tr>\n  {% for a in historial %}\n  <tr><td>{{ a.fecha.strftime(\'%d/%m/%Y %H:%M\') }}</td>\n      <td>{{ a.usuario }}</td><td>{{ a.accion }}</td></tr>\n  {% endfor %}\n</table>\n{% endif %}\n\n<div style="margin-top:16px">\n  <a class="btn btn-verde" href="{{ url_for(\'main.exportar\', id=e.id) }}">Exportar Excel</a>\n  <a class="btn btn-gris" href="{{ url_for(\'main.dashboard\') }}">Volver</a>\n</div>\n{% endblock %}\n',

}
